    return result;
}

int discrete_logarithm(long long base, long long target, long long modulus) {
    if (modulus == 1) return 0;
    int m = (int)ceil(sqrt((double)modulus));

    unordered_map<long long, int> table;
    long long power = 1;
    for (int j = 0; j < m; j++) {
        if (power == target % modulus) return j;
        table[power] = j;
        power = power * base % modulus;
    }

    long long base_inv_m = mod_pow(base, modulus - 1 - (m % (modulus - 1)), modulus);
    long long gamma = target % modulus;
    for (int i = 0; i < m; i++) {
        auto it = table.find(gamma);
        if (it != table.end()) return i * m + it->second;
        gamma = gamma * base_inv_m % modulus;
    }
    return -1;
}

