func modPow(base, exp, mod int64) int64 {
	result := int64(1)
	base %= mod
	for exp > 0 {
		if exp&1 == 1 {
			result = result * base % mod
		}
		exp >>= 1
		base = base * base % mod
	}
	return result
}

func discreteLogarithm(base, target, modulus int64) int {
	if modulus == 1 {
		return 0
	}
	m := int64(math.Ceil(math.Sqrt(float64(modulus))))
	target %= modulus

	table := make(map[int64]int)
	power := int64(1)
	for j := int64(0); j < m; j++ {
		if power == target {
			return int(j)
		}
		table[power] = int(j)
		power = power * base % modulus
	}

	baseInvM := modPow(base, modulus-1-(m%(modulus-1)), modulus)
	gamma := target
	for i := int64(0); i < m; i++ {
		if j, ok := table[gamma]; ok {
			return int(i)*int(m) + j
		}
		gamma = gamma * baseInvM % modulus
	}
	return -1
}

