use std::collections::HashMap;

fn mod_pow(mut base: i64, mut exp: i64, modulus: i64) -> i64 {
    let mut result = 1i64;
    base %= modulus;
    while exp > 0 {
        if exp & 1 == 1 { result = result * base % modulus; }
        exp >>= 1;
        base = base * base % modulus;
    }
    result
}

fn discrete_logarithm(base: i64, target: i64, modulus: i64) -> i32 {
    if modulus == 1 { return 0; }
    let m = (modulus as f64).sqrt().ceil() as i64;
    let target = target % modulus;

    let mut table = HashMap::new();
    let mut power = 1i64;
    for j in 0..m {
        if power == target { return j as i32; }
        table.insert(power, j);
        power = power * base % modulus;
    }

    let base_inv_m = mod_pow(base, modulus - 1 - (m % (modulus - 1)), modulus);
    let mut gamma = target;
    for i in 0..m {
        if let Some(&j) = table.get(&gamma) {
            return (i * m + j) as i32;
        }
        gamma = gamma * base_inv_m % modulus;
    }
    -1
}

